/**
 * API Route: Contact Sales Buttons Management
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import { verifyToken } from '@/lib/auth';

const prisma = new PrismaClient();

export const dynamic = 'force-dynamic';

// GET: لیست تمام دکمه‌های Contact Sales
export async function GET(request: NextRequest) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const buttons = await prisma.contactSalesButton.findMany({
      orderBy: { language: 'asc' },
    });

    return NextResponse.json({ 
      success: true,
      buttons: buttons.map(btn => ({
        ...btn,
        style: btn.style ? JSON.parse(btn.style) : null
      }))
    });
  } catch (error) {
    console.error('Contact Sales GET error:', error);
    return NextResponse.json({ 
      success: false,
      error: 'Internal server error' 
    }, { status: 500 });
  }
}

// POST: ایجاد دکمه جدید
export async function POST(request: NextRequest) {
  try {
    const authHeader = request.headers.get('authorization');
    const token = authHeader?.replace('Bearer ', '');
    
    if (!token || !verifyToken(token)) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const data = await request.json();

    // چک کردن اینکه دکمه برای این زبان وجود نداره
    const existing = await prisma.contactSalesButton.findUnique({
      where: { language: data.language }
    });

    if (existing) {
      return NextResponse.json({ 
        success: false,
        error: `Contact Sales button for language "${data.language}" already exists` 
      }, { status: 400 });
    }

    const button = await prisma.contactSalesButton.create({
      data: {
        language: data.language,
        show: data.show !== undefined ? data.show : true,
        text: data.text,
        url: data.url,
        style: data.style ? JSON.stringify(data.style) : null,
        isActive: data.isActive !== undefined ? data.isActive : true
      },
    });

    return NextResponse.json({ 
      success: true,
      button 
    });
  } catch (error) {
    console.error('Contact Sales POST error:', error);
    return NextResponse.json({ 
      success: false,
      error: 'Internal server error' 
    }, { status: 500 });
  }
}
